const currentItem = $input.first();
const current = currentItem.json || {};

let original = {};
try {
  original = $('Decide AI mode').first().json || {};
} catch (e) {
  original = {};
}

const item = {
  ...original,
  ...current,

  user_id: original.user_id || current.user_id,
  chat_id: original.chat_id || current.chat_id,
  pending_message_id: original.pending_message_id || current.pending_message_id,
  message_uuid: original.message_uuid || current.message_uuid,

  message_type: original.message_type || current.message_type,
  file_id: original.file_id || current.file_id,
  file_unique_id: original.file_unique_id || current.file_unique_id,
  file_name: original.file_name || current.file_name,
  mime_type: original.mime_type || current.mime_type,
  caption: original.caption || current.caption,
  message: original.message || current.message,
  content: original.content || current.content,

  telegram_file_path:
    current.result?.file_path ||
    current.file_path ||
    original.telegram_file_path ||
    current.telegram_file_path,

  file_url: original.file_url || current.file_url
};

function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

function safeString(value, fallback = '') {
  if (value === undefined || value === null) return fallback;
  return String(value);
}

function getExtension(fileName) {
  const match = safeString(fileName).toLowerCase().match(/\.([a-z0-9]+)$/);
  return match ? match[1] : '';
}

function uniqueArray(values) {
  return [
    ...new Set(
      values
        .filter(v => v !== undefined && v !== null && String(v).trim() !== '')
        .map(v => String(v).trim())
    )
  ];
}

function truncateText(text, maxChars) {
  const str = safeString(text);
  if (str.length <= maxChars) return str;

  return (
    str.slice(0, maxChars) +
    `\n\n[Content truncated to ${maxChars} characters for safe AI analysis]`
  );
}

function normalizeMimeType(mimeType, ext, messageType) {
  const mt = safeString(mimeType).toLowerCase();

  if (mt && mt !== 'application/octet-stream') {
    return mt;
  }

  if (messageType === 'photo') {
    if (ext === 'png') return 'image/png';
    if (ext === 'webp') return 'image/webp';
    if (ext === 'heic') return 'image/heic';
    return 'image/jpeg';
  }

  if (ext === 'jpg' || ext === 'jpeg') return 'image/jpeg';
  if (ext === 'png') return 'image/png';
  if (ext === 'webp') return 'image/webp';
  if (ext === 'heic') return 'image/heic';

  if (ext === 'pdf') return 'application/pdf';
  if (ext === 'json') return 'application/json';
  if (ext === 'xml') return 'application/xml';
  if (ext === 'txt') return 'text/plain';
  if (ext === 'csv') return 'text/csv';

  return mimeType || 'application/octet-stream';
}

async function findBinaryData() {
  const binary = currentItem.binary || {};
  const keys = Object.keys(binary);

  if (keys.length === 0) {
    return null;
  }

  const propertyName = keys.includes('data') ? 'data' : keys[0];
  const binaryMeta = binary[propertyName];

  if (!binaryMeta) {
    return null;
  }

  let buffer;

  try {
    buffer = await this.helpers.getBinaryDataBuffer(0, propertyName);
  } catch (error) {
    return {
      data: null,
      mimeType: binaryMeta.mimeType || binaryMeta.mime_type || null,
      fileName: binaryMeta.fileName || binaryMeta.file_name || null,
      fileSize: null,
      source: 'binary_buffer_read_failed',
      propertyName,
      error: error.message
    };
  }

  return {
    data: buffer.toString('base64'),
    mimeType: binaryMeta.mimeType || binaryMeta.mime_type || null,
    fileName: binaryMeta.fileName || binaryMeta.file_name || null,
    fileSize: buffer.length,
    source: 'binary_buffer_from_n8n_separate_mode',
    propertyName,
    error: null
  };
}

const userId = firstValue(item.user_id, item.from_id);
const chatId = firstValue(item.chat_id, userId);

const pendingMessageId = firstValue(item.pending_message_id, item.id);
const messageUuid = firstValue(item.message_uuid);

const messageType = safeString(item.message_type || 'document').toLowerCase();

let fileName = safeString(
  item.file_name ||
  item.message ||
  item.content ||
  item.telegram_file_path ||
  'file'
);

if (messageType === 'photo' && (!fileName || fileName === '[photo]')) {
  fileName = 'photo.jpg';
}

const ext = getExtension(fileName || item.telegram_file_path);

let mimeType = safeString(item.mime_type || 'application/octet-stream');
mimeType = normalizeMimeType(mimeType, ext, messageType);

const caption = safeString(item.caption || '');
const telegramFilePath = safeString(item.telegram_file_path || '');
const fileUrl = safeString(item.file_url || '');
const originalMessage = safeString(item.message || item.content || caption || fileName);

const binaryData = await findBinaryData();

if (binaryData?.mimeType) {
  mimeType = normalizeMimeType(binaryData.mimeType, ext, messageType);
}

const isInlineSupportedFile =
  messageType === 'photo' ||
  mimeType.startsWith('image/') ||
  mimeType === 'application/pdf' ||
  ['jpg', 'jpeg', 'png', 'webp', 'heic', 'pdf'].includes(ext);

const supportedGeminiInlineMimeTypes = [
  'image/jpeg',
  'image/png',
  'image/webp',
  'image/heic',
  'application/pdf'
];

const hasInlineData =
  isInlineSupportedFile &&
  Boolean(binaryData?.data) &&
  supportedGeminiInlineMimeTypes.includes(mimeType);

const readableContent = safeString(
  item.extracted_text ||
  item.file_text ||
  item.downloaded_text ||
  item.text_content ||
  item.content_for_ai ||
  ''
);

const readableContentForAi = truncateText(readableContent, 12000);

const technicalExtensions = [
  'json', 'xml', 'sql', 'js', 'ts', 'tsx', 'jsx', 'yaml', 'yml', 'csv', 'txt', 'md', 'html', 'css', 'log', 'env'
];

const documentExtensions = [
  'pdf', 'doc', 'docx', 'xls', 'xlsx', 'ppt', 'pptx'
];

const oldBinaryExtensions = ['doc', 'xls', 'ppt'];

const isTechnicalFile =
  technicalExtensions.includes(ext) ||
  mimeType.includes('json') ||
  mimeType.includes('xml') ||
  mimeType.includes('text') ||
  mimeType.includes('csv') ||
  mimeType.includes('yaml');

const isDocumentFile =
  documentExtensions.includes(ext) ||
  mimeType.includes('pdf') ||
  mimeType.includes('word') ||
  mimeType.includes('officedocument') ||
  mimeType.includes('excel') ||
  mimeType.includes('spreadsheet') ||
  mimeType.includes('powerpoint') ||
  mimeType.includes('presentation');

const isOldBinaryFile = oldBinaryExtensions.includes(ext);

const looksLikeN8nWorkflow =
  fileName.toLowerCase().includes('workflow') ||
  fileName.toLowerCase().includes('n8n') ||
  readableContent.includes('"nodes"') ||
  readableContent.includes('"connections"') ||
  readableContent.includes('"type": "n8n-nodes-base');

const looksLikeDatabaseSchema =
  ext === 'sql' ||
  readableContent.toLowerCase().includes('create table') ||
  readableContent.toLowerCase().includes('alter table') ||
  readableContent.toLowerCase().includes('create schema');

const looksLikeConfig =
  ['json', 'xml', 'yaml', 'yml', 'env'].includes(ext) ||
  fileName.toLowerCase().includes('config') ||
  fileName.toLowerCase().includes('settings');

const shouldAnalyzeFileInitial = item.should_analyze_file !== false;

const skipGeminiAnalysis =
  !shouldAnalyzeFileInitial ||
  (isOldBinaryFile && !readableContent);

const fallbackMetadata = {
  summary: `File saved: ${fileName}`,
  category: ext === 'pdf' ? 'document' : (isInlineSupportedFile ? 'photo' : 'file'),
  language: 'unknown',
  entities: uniqueArray([
    looksLikeN8nWorkflow ? 'n8n' : null,
    fileName.toLowerCase().includes('memoraq') ? 'Memoraq' : null
  ]),
  important_details: uniqueArray([
    `File name: ${fileName}`,
    `File extension: ${ext || 'unknown'}`,
    `MIME type: ${mimeType}`
  ]),
  confidence: hasInlineData ? 0.6 : 0.35
};

if (skipGeminiAnalysis) {
  return [
    {
      json: {
        ...item,
        user_id: userId,
        chat_id: chatId,
        pending_message_id: pendingMessageId,
        message_uuid: messageUuid,
        message_type: messageType,
        file_name: fileName,
        mime_type: mimeType,
        caption,
        telegram_file_path: telegramFilePath,
        file_url: fileUrl,
        file_extension: ext,
        ai_mode: 'fallback',
        should_analyze_file: false,
        skip_gemini_analysis: true,
        ai_summary: fallbackMetadata.summary,
        ai_category: fallbackMetadata.category,
        ai_language: fallbackMetadata.language,
        ai_entities: fallbackMetadata.entities,
        ai_important_details: fallbackMetadata.important_details,
        ai_confidence: fallbackMetadata.confidence
      }
    }
  ];
}

let prompt = `
You are an expert AI data extractor. Your task is to analyze the attached file/image and extract its metadata.

CRITICAL INSTRUCTIONS FOR LANGUAGE DETECTION:
1. First, visually inspect and perform OCR on the image to read the actual text written inside the document.
