function firstValue(...values) {
  for (const value of values) {
    if (value !== undefined && value !== null && value !== '') {
      return value;
    }
  }
  return null;
}

function safeString(value, fallback = '') {
  if (value === undefined || value === null) return fallback;
  return String(value);
}

function stripCodeFences(text) {
  return safeString(text)
    .replace(/^```json\s*/i, '')
    .replace(/^```\s*/i, '')
    .replace(/```$/i, '')
    .trim();
}

function parseJsonFromText(text) {
  const raw = stripCodeFences(text);
  if (!raw) return null;
  try {
    return JSON.parse(raw);
  } catch (e) {}

  const match = raw.match(/\{[\s\S]*\}/);
  if (match) {
    try {
      return JSON.parse(match[0]);
    } catch (e) {}
  }
  return null;
}

function cleanString(value, maxLength = 600) {
  const str = safeString(value).replace(/\s+/g, ' ').trim();
  if (str.length <= maxLength) return str;
  return str.slice(0, maxLength).trim();
}

function extractGeminiText(response) {
  const directText = safeString(response.text || response.ai_raw_text || '').trim();
  if (directText) return directText;

  return response.candidates?.[0]?.content?.parts
    ?.map(part => part.text || '')
    .join('\n')
    .trim() || '';
}

// Новая умная функция детекции языка
function detectLanguageFromText(text, fallback = 'unknown') {
  const str = safeString(text);

  // 1. Если в сопутствующем тексте физически есть буквы иврита — это иврит
  if (/[\u0590-\u05FF]/.test(str)) {
    return 'he';
  }
  // 2. Если в сопутствующем тексте есть кириллица — это русский
  if (/[\u0400-\u04FF]/.test(str)) {
    return 'ru';
  }

  // 3. Если физического текста нет (как в JPG ветке), безоговорочно доверяем JSON-ответу Gemini
  const fb = String(fallback || '').toLowerCase().trim();
  if (fb === 'he' || fb === 'hebrew') return 'he';
  if (fb === 'ru' || fb === 'russian') return 'ru';
  if (fb === 'en' || fb === 'english') return 'en';

  return fb && fb !== 'unknown' ? fb : 'en';
}

